head.script:
scwin.onpageload = function () {
    console.log("[DAM] onpageload fired");
    scwin._setActive(0);
};

scwin._setActive = function (idx) {
    console.log("[DAM] _setActive called, idx=" + idx);
    var ids    = ["btn_navDashboard","btn_navFileBrowser","btn_navAssetDetails","btn_navVersionControl"];
    var titles = ["Dashboard","File Browser","Asset Details Panel","Version Control"];
    for (var i = 0; i < ids.length; i++) {
        var comp = $p.getComponentById(ids[i]);
        if (comp) { comp.removeClass("dam-active"); }
    }
    var activeComp = $p.getComponentById(ids[idx]);
    if (activeComp) { activeComp.addClass("dam-active"); }
    try {
        var titleComp = $p.getComponentById("txt_pageTitle");
        if (titleComp) { titleComp.setLabel(titles[idx]); }
    } catch (e) { console.warn("[DAM] setLabel error", e); }
    scwin._switchTab(idx, 0);
};

scwin._switchTab = function (idx, attempt) {
    var tab = $p.getComponentById("tab_main");
    console.log("[DAM] _switchTab attempt=" + attempt + " tab=" + tab + " idx=" + idx);
    if (tab) {
        console.log("[DAM] tab methods:", typeof tab.setSelectedTabIndex, typeof tab.setSelectedTab);
    }
    if (tab && typeof tab.setSelectedTabIndex === "function") {
        try { tab.setSelectedTabIndex(idx); console.log("[DAM] setSelectedTabIndex OK"); return; } catch (e) { console.warn("[DAM] setSelectedTabIndex error", e); }
    }
    if (attempt < 10) {
        window.setTimeout(function () { scwin._switchTab(idx, attempt + 1); }, 150);
    } else {
        console.error("[DAM] tab_main not ready after 10 attempts");
    }
};

scwin.btn_navDashboard_onclick      = function () { console.log("[DAM] click Dashboard");      scwin._setActive(0); };
scwin.btn_navFileBrowser_onclick    = function () { console.log("[DAM] click FileBrowser");    scwin._setActive(1); };
scwin.btn_navAssetDetails_onclick   = function () { console.log("[DAM] click AssetDetails");   scwin._setActive(2); };
scwin.btn_navVersionControl_onclick = function () { console.log("[DAM] click VersionControl"); scwin._setActive(3); };

scwin.btn_logout_onclick = function () {
    if (confirm("Logout?")) { location.href = "/"; }
};

scwin.img_hamburger_onclick = function () {
    var shell = $p.getComponentById("grp_appShell");
    if (shell) {
        if (shell.hasClass("dam-sidebar-collapsed")) {
            shell.removeClass("dam-sidebar-collapsed");
        } else {
            shell.addClass("dam-sidebar-collapsed");
        }
    }
};
